siem_queries.chronicle_yara_l:
rule context_poisoning_retrieval {
  events:
    (($e.metadata.event_type = "secure_context.retrieval" or $e.metadata.event_type = "context.poisoning_scan" or $e.metadata.event_type = "policy.decision")) and ((($e.principal.labels.poisoning_scan_state = "critical" or $e.principal.labels.poisoning_scan_state = "high" or $e.principal.labels.poisoning_scan_state = "failed_open") or ($e.principal.labels.context_retrieval_decision = "deny_context_poisoning" or $e.principal.labels.context_retrieval_decision = "kill_session_on_context_poisoning")))
  condition:
    $e
}

rule mcp_token_passthrough_or_audience_mismatch {
  events:
    (($e.metadata.event_type = "mcp.tools.call" or $e.metadata.event_type = "policy.decision")) and (($e.principal.labels.authorization_token_passthrough_detected = "true" or $e.principal.labels.authorization_audience_mismatch = "true" or ($e.principal.labels.authorization_decision = "deny_token_passthrough" or $e.principal.labels.authorization_decision = "kill_token_passthrough" or $e.principal.labels.authorization_decision = "deny_audience_mismatch")))
  condition:
    $e
}

rule secret_or_cross_tenant_telemetry {
  events:
    (($e.principal.labels.telemetry_contains_secret = "true" or $e.principal.labels.telemetry_cross_tenant_context = "true" or ($e.principal.labels.telemetry_redaction_state = "raw_secret" or $e.principal.labels.telemetry_redaction_state = "unredacted_pii" or $e.principal.labels.telemetry_redaction_state = "cross_tenant")))
  condition:
    $e
}

rule approval_bypass_high_impact_action {
  events:
    (($e.principal.labels.action_impact_class = "high" or $e.principal.labels.action_impact_class = "critical" or $e.principal.labels.action_impact_class = "irreversible")) and (($e.principal.labels.approval_decision = "missing" or $e.principal.labels.approval_decision = "expired" or $e.principal.labels.approval_decision = "declined" or $e.principal.labels.approval_decision = "bypassed"))
  condition:
    $e
}

rule browser_agent_url_exfiltration {
  events:
    (($e.principal.labels.destination_class = "external" or $e.principal.labels.destination_class = "public_internet" or $e.principal.labels.destination_class = "unknown")) and ((($e.principal.labels.egress_decision = "deny_context_egress" or $e.principal.labels.egress_decision = "kill_session_on_egress" or $e.principal.labels.egress_decision = "hold_for_egress_review") or $e.principal.labels.browser_prompt_injection_signal = "true" or $e.principal.labels.browser_sends_external_message = "true"))
  condition:
    $e
}

rule mcp_tool_surface_drift_critical {
  events:
    ($e.principal.labels.tool_surface_drift_detected = "true") and ((($e.principal.labels.tool_surface_drift_severity = "critical" or $e.principal.labels.tool_surface_drift_severity = "high") or ($e.principal.labels.policy_decision = "hold_for_tool_surface_review" or $e.principal.labels.policy_decision = "deny_tool_surface_drift" or $e.principal.labels.policy_decision = "kill_session_on_tool_surface_drift")))
  condition:
    $e
}

rule red_team_replay_regression {
  events:
    (($e.principal.labels.replay_status = "failed" or $e.principal.labels.replay_status = "regressed")) and (($e.principal.labels.replay_observed_decision != $e.principal.labels.replay_expected_decision or ($e.principal.labels.policy_decision = "hold_for_replay_failure" or $e.principal.labels.policy_decision = "deny_release_on_replay_regression")))
  condition:
    $e
}

rule shadow_mcp_server_or_unknown_connector {
  events:
    (($e.principal.labels.mcp_server_registry_status = "unknown" or $e.principal.labels.mcp_server_registry_status = "unregistered" or $e.principal.labels.mcp_server_registry_status = "quarantined")) and ((($e.principal.labels.mcp_server_trust_tier = "unknown" or $e.principal.labels.mcp_server_trust_tier = "experimental" or $e.principal.labels.mcp_server_trust_tier = "blocked") or ($e.principal.labels.policy_decision = "deny_unregistered_connector" or $e.principal.labels.policy_decision = "hold_for_connector_intake" or $e.principal.labels.policy_decision = "kill_session_on_shadow_mcp")))
  condition:
    $e
}

rule source_freshness_or_standard_drift {
  events:
    ((($e.principal.labels.source_freshness_decision = "stale" or $e.principal.labels.source_freshness_decision = "hold_for_source_refresh" or $e.principal.labels.source_freshness_decision = "standards_changed") or $e.principal.labels.standards_changed = "true"))
  condition:
    $e
}

rule unbounded_agent_loop_or_cost_runaway {
  events:
    (($e.principal.labels.loop_iteration_count >= 8 or $e.principal.labels.budget_tokens_pct >= 90 or $e.principal.labels.budget_cost_pct >= 90))
  condition:
    $e
}
